import React from "react";
import ReactDOM from "react-dom/client";
import "./index.css";
import App from "./App";
import reportWebVitals from "./reportWebVitals";
import { ClerkProvider, ClerkLoaded, ClerkLoading, ClerkFailed } from "@clerk/clerk-react";

const originalError = console.error;
console.error = (...args) => {
  if (typeof args[0] === "string" && args[0].includes("ResizeObserver")) {
    return;
  }
  originalError(...args);
};

const clerkPublishableKey = process.env.REACT_APP_CLERK_PUBLISHABLE_KEY;

function MissingClerkConfig() {
  return (
    <div style={{ minHeight: "100vh", display: "grid", placeItems: "center", padding: 24 }}>
      <div style={{
        maxWidth: 700,
        borderRadius: 14,
        padding: 24,
        background: "linear-gradient(160deg,#ede8dc,#d8d0c0)",
        boxShadow: "8px 8px 20px rgba(0,0,0,.25), -6px -6px 14px rgba(255,255,255,.85)",
      }}>
        <h2 style={{ marginTop: 0 }}>Missing Clerk configuration</h2>
        <p style={{ marginBottom: 0 }}>
          Set <code>REACT_APP_CLERK_PUBLISHABLE_KEY</code> in <code>frontend/charlie_client/.env</code> and restart the frontend server.
        </p>
      </div>
    </div>
  );
}

function ClerkInitializing() {
  return (
    <div style={{ minHeight: "100vh", display: "grid", placeItems: "center", padding: 24 }}>
      <div style={{
        maxWidth: 700,
        borderRadius: 14,
        padding: 24,
        background: "linear-gradient(160deg,#ede8dc,#d8d0c0)",
        boxShadow: "8px 8px 20px rgba(0,0,0,.25), -6px -6px 14px rgba(255,255,255,.85)",
      }}>
        <h2 style={{ marginTop: 0 }}>Initializing Clerk</h2>
        <p style={{ marginBottom: 0 }}>Loading authentication provider...</p>
      </div>
    </div>
  );
}

function ClerkInitFailed() {
  return (
    <div style={{ minHeight: "100vh", display: "grid", placeItems: "center", padding: 24 }}>
      <div style={{
        maxWidth: 800,
        borderRadius: 14,
        padding: 24,
        background: "linear-gradient(160deg,#ede8dc,#d8d0c0)",
        boxShadow: "8px 8px 20px rgba(0,0,0,.25), -6px -6px 14px rgba(255,255,255,.85)",
      }}>
        <h2 style={{ marginTop: 0 }}>Clerk failed to initialize</h2>
        <p style={{ marginBottom: 8 }}>
          Verify your Clerk key and allow <code>http://localhost:3000</code> in Clerk app settings.
        </p>
        <p style={{ marginBottom: 0 }}>
          Then restart the frontend server.
        </p>
      </div>
    </div>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    {clerkPublishableKey ? (
      <ClerkProvider publishableKey={clerkPublishableKey}>
        <ClerkLoading>
          <ClerkInitializing />
        </ClerkLoading>
        <ClerkFailed>
          <ClerkInitFailed />
        </ClerkFailed>
        <ClerkLoaded>
          <App />
        </ClerkLoaded>
      </ClerkProvider>
    ) : (
      <MissingClerkConfig />
    )}
  </React.StrictMode>
);

reportWebVitals();
