import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { useState, useEffect, useCallback } from "react";
import { SignedIn, SignedOut, RedirectToSignIn, useAuth } from "@clerk/clerk-react";
import Dashboard from "./Pages/Dashboard";
import Hierarchy from "./Pages/Hierarchy";
import HDL from "./Pages/HDL";
import Sidebar from "./Components/sidebar";
import Topbar from "./Components/Topbar";
import api, { setAuthTokenGetter } from "./services/api";
import Configuration from "./Pages/Configuration";
import PostValidation from "./Pages/Post_Validation";
import Onboarding from "./Pages/Onboarding";
import "./App.css";
import SignInPage from "./auth/SignInPage";
import SignUpPage from "./auth/SignUpPage";
import UserProfilePage from "./auth/UserProfilePage";

/* -------------------- Layout Wrapper -------------------- */

function AppContent() {
  const location = useLocation();
  const isAuthRoute =
    location.pathname.startsWith("/sign-in") ||
    location.pathname.startsWith("/sign-up");
  const showTopbar =
    location.pathname !== "/hdl" &&
    !location.pathname.startsWith("/user-profile");

  if (isAuthRoute) {
    return (
      <>
        <SignedIn>
          <Navigate to="/" replace />
        </SignedIn>
        <SignedOut>
          <Routes>
            <Route path="/sign-in/*" element={<SignInPage />} />
            <Route path="/sign-up/*" element={<SignUpPage />} />
            <Route path="*" element={<Navigate to="/sign-in" replace />} />
          </Routes>
        </SignedOut>
      </>
    );
  }

  return (
    <>
      <SignedIn>
        <div className="layout fade-in">
          <Sidebar />
          <div className="main-container">
            {showTopbar && <Topbar />}
            <div style={{ flex: 1, display: "flex", flexDirection: "column", minHeight: 0, overflow: "auto" }}>
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/dashboard" element={<Dashboard />} />
                <Route path="/hierarchy" element={<Hierarchy />} />
                <Route path="/hdl" element={<HDL />} />
                <Route path="/config" element={<Configuration />} />
                <Route path="/post-validation" element={<PostValidation />} />
                <Route path="/onboarding" element={<Onboarding />} />
                <Route path="/user-profile/*" element={<UserProfilePage />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </div>
          </div>
        </div>
      </SignedIn>
      <SignedOut>
        <RedirectToSignIn />
      </SignedOut>
    </>
  );
}

/* -------------------- Main App -------------------- */

function App() {
  const { getToken, isLoaded, isSignedIn } = useAuth();
  const [loading, setLoading] = useState(true);
  const [serverStatus, setServerStatus] = useState("checking");
  const [checking, setChecking] = useState(false);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    setAuthTokenGetter(async () => {
      const template = process.env.REACT_APP_CLERK_JWT_TEMPLATE;
      if (template) {
        return getToken({ template });
      }
      return getToken();
    });

    return () => {
      setAuthTokenGetter(null);
    };
  }, [getToken]);

  const checkServer = useCallback(async () => {
    setChecking(true);
    setLoading(true);
    setSuccess(false);
    try {
      await api.get("/health");
      setServerStatus("UP");
      setSuccess(true);

      setTimeout(() => {
        setLoading(false);
      }, 1500);
    } catch (err) {
      setServerStatus("DOWN");
      setLoading(false);
    } finally {
      setChecking(false);
    }
  }, []);

  useEffect(() => {
    if (isSignedIn) {
      checkServer();
      return;
    }

    setLoading(false);
    setSuccess(false);
    setServerStatus("checking");
  }, [checkServer, isSignedIn]);

  if (!isLoaded) {
    return (
      <div className="center-screen neo-container">
        <div className="neo-card">
          <div className="spinner"></div>
          <h2>Loading Authentication</h2>
          <p>Preparing secure session</p>
        </div>
      </div>
    );
  }

  // Signed-out users should always reach Clerk screens, regardless of backend status.
  if (!isSignedIn) {
    return (
      <Router>
        <AppContent />
      </Router>
    );
  }

  if (loading && !success) {
    return (
      <div className="center-screen neo-container">
        <div className="neo-card">
          <div className="spinner"></div>
          <h2>Connecting to Charlie Engine</h2>
          <p>Initializing HDL Management Platform</p>
        </div>
      </div>
    );
  }

  if (success && loading) {
    return (
      <div className="center-screen neo-container">
        <div className="neo-card success-card">
          <div className="success-check">OK</div>
          <h2>Connection Established</h2>
          <p>Charlie Engine is Online</p>
        </div>
      </div>
    );
  }

  if (serverStatus !== "UP") {
    return (
      <div className="center-screen neo-container">
        <div className="neo-card error-card">
          <div className="warning-icon">!</div>
          <h2>Backend Service Unavailable</h2>
          <button
            className="neo-button"
            onClick={checkServer}
            disabled={checking}
          >
            {checking ? "Checking..." : "Recheck Server"}
          </button>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
