import axios from "axios";

const api = axios.create({
  baseURL: "http://localhost:8000/api",
  timeout: 300000, // 5 min default; large-scale validation overrides per-request
});

let authTokenGetter = null;

export const setAuthTokenGetter = (getter) => {
  authTokenGetter = typeof getter === "function" ? getter : null;
};

/* ---------- REQUEST INTERCEPTOR ---------- */
api.interceptors.request.use(async (config) => {
  config.headers = config.headers || {};

  if (authTokenGetter && !config.headers.Authorization) {
    try {
      const token = await authTokenGetter();
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
    } catch (error) {
      console.warn("Unable to attach Clerk token:", error);
    }
  }

  // If body is FormData, remove JSON header.
  if (config.data instanceof FormData) {
    delete config.headers["Content-Type"];
  }

  return config;
});

/* ---------- RESPONSE INTERCEPTOR ---------- */
api.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error("API Error:", error.response?.data || error.message);
    return Promise.reject(error);
  }
);

export default api;
